import './Notifications.scss';

import { Icon } from ':components/Icon';
import { IconButton } from ':components/IconButton';
import { Menu, MenuItem } from ':components/Menu';
import { NewDropdownMenu } from ':components/NewDropdownMenu';
import { Typography } from ':components/Typography';
import { classNames } from ':helpers/classnames';
import { useDeviceSize } from ':helpers/use-device-size';
import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import type { ReactNode } from 'react';
import React, { useRef } from 'react';

import type { NotificationsProps } from './Notifications.types';

export const Notifications: React.FC<NotificationsProps> = ({
	className,
	dataTestId = 'Notifications',
	isOpen,
	targetElement,
	handleSetOpen,
	error,
	value = [],
	onRefresh,
	onShowAll,
	onReadAll,
	mobileOnGoBack,
	mobileHeaderMenu,
	...props
}) => {
	const { isExtraSmallDevice } = useDeviceSize();
	const mobileHeaderMenuIconRef = useRef<HTMLButtonElement | null>(null);

	const StatesScreen = ({
		iconName,
		title,
		subtitle,
		onRefresh,
	}: { iconName: Icons; title: string; subtitle: string } & Pick<NotificationsProps, 'onRefresh'>) => (
		<div className={'dsb_notifications-state'}>
			<Icon type={onRefresh ? 'error' : 'default'} contained iconName={iconName} />
			<Typography className={'dsb_notifications-state__caption'} variant={'body2'}>
				{title}
			</Typography>
			<Typography className={'dsb_notifications-state__caption'} variant={'body3'}>
				{subtitle}
			</Typography>
			{onRefresh && (
				<div className="dsb_notifications-state__refresh" onClick={onRefresh}>
					<Icon className="dsb_notifications-state__refresh__icon" iconName={Icons.Refresh} /> Обновить
				</div>
			)}
		</div>
	);

	const DefaultScreen = ({
		value,
		onReadAll,
		onShowAll,
	}: Pick<NotificationsProps, 'value' | 'onReadAll' | 'onShowAll'>) => (
		<>
			<div className={'dsb_notifications__content-wrapper'}>
				<ul role="list" className={'dsb_notifications__content'}>
					{value.map((item, index) => (
						<li role="listitem" key={index} className={'dsb_notifications__content__item'}>
							{item}
						</li>
					))}
				</ul>
			</div>
			{!isExtraSmallDevice && (
				<div className={'dsb_notifications__controls'}>
					{onReadAll && (
						<p onClick={onReadAll} className={'dsb_notifications__controls__link'}>
							Прочитать все
						</p>
					)}
					{onShowAll && (
						<p onClick={onShowAll} className={'dsb_notifications__controls__link'}>
							Все уведомления
						</p>
					)}
				</div>
			)}
		</>
	);

	const NotificationsContent = ({
		value,
		error,
		onRefresh,
		onShowAll,
		onReadAll,
	}: Pick<NotificationsProps, 'value' | 'error' | 'onRefresh' | 'onShowAll' | 'onReadAll'>) => {
		if (error) {
			return (
				<StatesScreen
					iconName={Icons.WarningCircled}
					title="Не удалось загрузить список уведомлений"
					subtitle="Проверьте подключение к интернету"
					onRefresh={onRefresh}
				/>
			);
		}
		if (value.length === 0) {
			return (
				<StatesScreen
					iconName={Icons.PageEmpty}
					title="Список уведомлений пуст"
					subtitle="Здесь будет отображаться список ваших уведомлений"
				/>
			);
		}

		return <DefaultScreen value={value} onReadAll={onReadAll} onShowAll={onShowAll} />;
	};

	const NotificationContainer = ({ children }: { children?: ReactNode }) => (
		<div
			data-testid={dataTestId}
			className={classNames('dsb_notifications', isExtraSmallDevice && 'dsb_notifications-mobile', className)}
			aria-live="polite"
			aria-atomic="false"
			aria-relevant="additions"
			role="region"
			{...props}
		>
			{children}
			<NotificationsContent
				value={value}
				error={error}
				onRefresh={onRefresh}
				onReadAll={onReadAll}
				onShowAll={onShowAll}
			/>
		</div>
	);

	return (
		isOpen &&
		(isExtraSmallDevice ? (
			<NotificationContainer>
				<div className="dsb_notifications__header">
					<IconButton onClick={mobileOnGoBack} size="large" iconName={Icons.NavArrowLeft} />
					<Typography>Уведомления</Typography>

					{mobileHeaderMenu ? (
						<>
							<IconButton
								ref={mobileHeaderMenuIconRef}
								onClick={mobileHeaderMenu.onClick}
								color="#fff"
								size="large"
								iconName={Icons.Settings}
							/>
							<Menu
								widthMode="widthContent"
								onOutsideClick={() => {
									mobileHeaderMenu.onOutsideClick();
								}}
								isOpen={mobileHeaderMenu.isOpen}
								parent={mobileHeaderMenuIconRef}
							>
								{mobileHeaderMenu.items.map((item, index) => (
									<MenuItem key={index} {...item} />
								))}
							</Menu>
						</>
					) : (
						<p onClick={onReadAll} className={'dsb_notifications__controls__link'}>
							Прочитать все
						</p>
					)}
				</div>
			</NotificationContainer>
		) : (
			<NewDropdownMenu
				isOpen={isOpen}
				targetElement={targetElement}
				handleSetOpen={handleSetOpen}
				onOutsideClick={() => {
					handleSetOpen(false);
				}}
			>
				<NotificationContainer />
			</NewDropdownMenu>
		))
	);
};
